#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C;
        scanf("%lld %lld %lld", &A, &B, &C);
        int even = (A%2==0) + (B%2==0) + (C%2==0);
        int odd = 3 - even;
        if(even>0 && odd>0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

